func validateProtoName(name string) error {
	matched, err := regexp.MatchString(`^[a-zA-Z0-9_\-\.]+\.proto$`, name)
	if err != nil {
		return err
	}
	if !matched {
		return fmt.Errorf("invalid proto name format")
	}
	if strings.Contains(name, "..") || strings.Contains(name, "/") || strings.Contains(name, "\\") {
		return fmt.Errorf("proto name contains invalid path characters")
	}
	return nil
}

func sanitizeProtoContent(content string) error {
	if len(content) > 1024*1024 {
		return fmt.Errorf("proto definition too large (max 1MB)")
	}

	dangerousPatterns := []string{
		"import \"google/protobuf/compiler/plugin.proto\"",
		"exec",
		"system",
		"eval",
	}

	lowerContent := strings.ToLower(content)
	for _, pattern := range dangerousPatterns {
		if strings.Contains(lowerContent, strings.ToLower(pattern)) {
			return fmt.Errorf("proto contains potentially dangerous pattern: %s", pattern)
		}
	}

	return nil
}

